
.card {
  width: 100%;
  max-width: 880px;
  margin: 0 auto;
  padding: 14px;
  background: var(--ow-bg);
  border: 1px solid var(--ow-line);
  border-radius: 20px;
  box-shadow: 0 16px 40px rgba(9, 42, 58, 0.12);
  display: grid;
  gap: 12px;
}

.hero-card,
.panel,
.vibe-card {
  background: var(--ow-panel);
  border: 1px solid var(--ow-line);
  border-radius: 16px;
  backdrop-filter: blur(10px);
}

.hero-card,
.panel {
  padding: 14px;
}

.hero-card {
  background: linear-gradient(135deg, rgba(15, 141, 180, 0.16), rgba(255, 179, 71, 0.16)), var(--ow-panel-strong);
}

.hero-copy {
  margin-bottom: 12px;
}

.eyebrow {
  font-size: 0.72rem;
  font-weight: 700;
  letter-spacing: 0.18em;
  color: var(--ow-accent);
}

h1 {
  margin: 6px 0 4px;
  font-size: 1.45rem;
  line-height: 1.1;
}

.hero-summary {
  margin: 0;
  color: var(--ow-muted);
  font-size: 0.92rem;
}

.meta-grid,
.summary-grid,
.panel-grid,
.list-grid,
.vibe-grid {
  display: grid;
  gap: 10px;
}

.meta-grid {
  grid-template-columns: repeat(4, minmax(0, 1fr));
}

.meta-card {
  padding: 10px 12px;
  border-radius: 14px;
  background: rgba(255, 255, 255, 0.72);
  border: 1px solid rgba(16, 71, 98, 0.12);
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.meta-label,
.summary-label,
.foot-note,
.list-desc,
.meta-sub {
  color: var(--ow-muted);
}

.meta-label,
.summary-label {
  font-size: 0.72rem;
}

.meta-value {
  font-size: 0.98rem;
  line-height: 1.2;
}

.vibe-grid {
  grid-template-columns: repeat(3, minmax(0, 1fr));
}

.vibe-card {
  padding: 10px 12px;
}

.vibe-head,
.section-head,
.roster-top,
.mini-head {
  display: flex;
  justify-content: space-between;
  gap: 8px;
  align-items: center;
}

.vibe-head,
.mini-head {
  font-size: 0.78rem;
  margin-bottom: 6px;
}

.tab-row {
  display: flex;
  gap: 8px;
  flex-wrap: wrap;
}

.tab-btn {
  border: none;
  border-radius: 999px;
  background: rgba(255, 255, 255, 0.76);
  color: var(--ow-text);
  padding: 8px 14px;
  font-size: 0.82rem;
  font-weight: 700;
  cursor: pointer;
  transition: 0.18s ease;
}

.tab-btn.active {
  background: linear-gradient(135deg, rgba(15, 141, 180, 0.96), rgba(8, 118, 153, 0.96));
  color: white;
}

.panel-grid {
  grid-template-columns: repeat(2, minmax(0, 1fr));
}

.panel-wide {
  grid-column: span 2;
}

.section-title {
  font-size: 0.92rem;
  font-weight: 700;
}

.section-badge,
.status-pill,
.chip {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  border-radius: 999px;
  font-size: 0.72rem;
  line-height: 1.2;
}

.section-badge,
.status-pill {
  padding: 3px 8px;
  background: rgba(15, 141, 180, 0.1);
  border: 1px solid rgba(15, 141, 180, 0.16);
  color: var(--ow-accent);
}

.status-pill.muted {
  background: rgba(83, 115, 133, 0.1);
  border-color: rgba(83, 115, 133, 0.16);
  color: var(--ow-muted);
}

.tag-list,
.roster-list {
  display: grid;
  gap: 10px;
}

.tag-card,
.list-card,
.roster-card,
.summary-card {
  border-radius: 14px;
  background: rgba(255, 255, 255, 0.7);
  border: 1px solid rgba(16, 71, 98, 0.1);
  padding: 10px 12px;
  display: grid;
  gap: 4px;
}

.list-name,
.tag-name,
.hero-meta {
  font-weight: 700;
}

.chip-list {
  display: flex;
  flex-wrap: wrap;
  gap: 6px;
  margin-top: 4px;
}

.chip {
  padding: 3px 8px;
  background: rgba(255, 179, 71, 0.14);
  color: #8a5700;
}

.bar-stack {
  display: grid;
  gap: 10px;
  margin: 10px 0 8px;
}

.bar-track {
  width: 100%;
  height: 8px;
  border-radius: 999px;
  background: rgba(16, 71, 98, 0.08);
  overflow: hidden;
}

.bar-fill {
  height: 100%;
  border-radius: inherit;
}

.bar-fill.cyan,
.bar-fill.blue {
  background: linear-gradient(90deg, #16b3d7, #0f8db4);
}

.bar-fill.green {
  background: linear-gradient(90deg, #58d99e, #38b27f);
}

.bar-fill.amber {
  background: linear-gradient(90deg, #ffd166, #ffb347);
}

.bar-fill.red {
  background: linear-gradient(90deg, #ff8b7d, #ef5c6c);
}

.bar-fill.purple {
  background: linear-gradient(90deg, #a382ff, #7a63f1);
}

.summary-grid {
  grid-template-columns: repeat(2, minmax(0, 1fr));
}

.summary-card {
  text-align: center;
}

.summary-card strong {
  font-size: 1.2rem;
}

.hero-panel {
  align-content: start;
}

.hero-meta,
.foot-note {
  font-size: 0.78rem;
}

@media (max-width: 760px) {
  .meta-grid,
  .vibe-grid,
  .panel-grid,
  .summary-grid {
    grid-template-columns: 1fr;
  }

  .panel-wide {
    grid-column: span 1;
  }
}
